    atsKeywords: ['telesalud', 'telemedicina', 'atención virtual', 'monitoreo remoto de pacientes', 'visitas por video', 'Teladoc', 'Amwell', 'Doxy.me', 'compatible con HIPAA', 'mHealth', 'RPM', 'salud digital'],
