    searchIntents: ['cómo incluir experiencia en regulaciones FDA en el currículum', 'habilidades de cumplimiento FDA para currículum', 'experiencia regulatoria FDA para currículum'],
    relatedSkills: ['Cumplimiento GMP', 'Aseguramiento de Calidad', 'Ensayos Clínicos', 'Desarrollo de Fármacos', 'Buenas Prácticas Clínicas', 'Investigación Clínica', 'Protocolos IRB', 'Informática en Salud'],
    professionSlugs: ['cientifico-de-investigacion', 'farmaceutico', 'quimico', 'ingeniero-biomedico', 'epidemiologo'],
